import subprocess
from typing import List, Dict

def update_requirements_txt(requirements_lock_file_path: str, requirements_txt_path: str) -> None:
    """
    Update the requirements.txt with the hash from the requirements.lock file.
    
    Args:
        requirements_lock_file_path (str): Path to the lock file (requirements.lock)
        requirements_txt_path (str): Path to the requirements.txt
    """

    # Generate hashes for each requirement in the lock file
    output = subprocess.check_output(['pip-compile', '--generate-hashes', '-r', requirements_lock_file_path, '-o', 'temp_requirements.txt']).decode('utf-8')

    with open(requirements_txt_path, 'w') as f:
        f.write(output)

def update_pipfile(pipfile_path: str) -> None:
    """
    Update the Pipfile lock file by re-locking it.
    
    Args:
        pipfile_path (str): Path to the Pipfile
    """

    # Run poetry lock to regenerate the lock file
    subprocess.run(['poetry', 'lock'], check=True)

    with open(pipfile_path, 'r+') as f:
        lines = f.readlines()
        f.seek(0)
        
        # Remove any existing lock files
        for line in lines:
            if not line.strip().startswith('[') and not line.startswith('#'):
                f.write(line)
        f.truncate()

def generate_poetry_init(pipfile_path: str, poetry_init_path: str) -> None:
    """
    Generate a new Poetry init file.
    
    Args:
        pipfile_path (str): Path to the Pipfile
        poetry_init_path (str): Path to where the poetry init will be generated
    """

    # Run poetry init to generate a new init file
    subprocess.run(['poetry', 'init'], cwd=pipfile_path, check=True)

    # Move the init.toml to its final destination
    import shutil
    shutil.move(pipfile_path / 'pyproject.toml', poetry_init_path)